UPDATE custom_pages_i18n SET content = JSON_SET(content, '$.html', '<div class=\"editorial-content\"><div class=\"eyebrow mb-6\">Yasal Bilgilendirme</div><h1>Gizlilik ve Veri Güvenliği</h1><p>Kaman İlan olarak kişisel verilerinizin güvenliği bizim için en üst düzeyde önceliğe sahiptir. 6698 sayılı Kişisel Verilerin Korunması Kanunu (KVKK) kapsamında, platformumuzu kullanırken paylaştığınız her türlü veriyi sadece size daha iyi hizmet sunmak ve yasal yükümlülüklerimizi yerine getirmek amacıyla işliyoruz.</p><h2>Hangi Verileri Topluyoruz?</h2><p>Üyelik işlemleri sırasında adınız, e-posta adresiniz ve telefon numaranız gibi temel iletişim bilgilerinizi topluyoruz. Bu bilgiler, ilanlarınızın doğrulanması ve alıcılarla sağlıklı iletişim kurmanız için gereklidir.</p><h2>Verilerin Paylaşımı</h2><p>Kişisel verileriniz, açık rızanız olmaksızın üçüncü taraflarla reklam veya pazarlama amacıyla paylaşılmaz. Sadece adli makamların yasal talepleri doğrultusunda ilgili kurumlarla paylaşım yapılabilir.</p><blockquote>Güvenliğiniz, Kaman İlan güvencesi altındadır.</blockquote></div>') WHERE slug = 'gizlilik-politikasi';

UPDATE custom_pages_i18n SET content = JSON_SET(content, '$.html', '<div class=\"editorial-content\"><div class=\"eyebrow mb-6\">Şartlar & Koşullar</div><h1>Platform Kullanım Kuralları</h1><p>Kaman İlan platformuna hoş geldiniz. Bu platformu kullanarak aşağıda belirtilen şartları kabul etmiş sayılırsınız. Kurallarımız, yerel ticaretin huzurunu ve güvenini korumak amacıyla oluşturulmuştur.</p><h2>İlan Yayın Kuralları</h2><ul><li>Yanıltıcı, sahte veya yasa dışı içerik barındıran ilanlar yasaktır.</li><li>Her ilan, doğru kategori altında ve gerçek bilgilerle yayınlanmalıdır.</li><li>Kullanıcılar, yayınladıkları ilanların içeriğinden bizzat sorumludur.</li></ul><h2>Hesap Güvenliği</h2><p>Hesabınızın güvenliği sizin sorumluluğunuzdadır. Şifrenizi kimseyle paylaşmayınız. Şüpheli bir durum fark ettiğinizde lütfen destek birimimizle iletişime geçiniz.</p><blockquote>Dürüst ticaret, Kaman İlan\'ın temelidir.</blockquote></div>') WHERE slug = 'kullanim-kosullari';

UPDATE custom_pages_i18n SET content = JSON_SET(content, '$.html', '<div class=\"flex flex-col gap-16\"><div><div class=\"eyebrow mb-6\">Standartlarımız</div><h1 class=\"font-fraunces text-4xl md:text-5xl text-ink mb-8\">Kusursuz Deneyim, <em>Sürdürülebilir Güven</em></h1><p class=\"text-lg text-text-2 leading-relaxed\">Kaman İlan kalitesini; şeffaf bilgi paylaşımı, kullanıcı dostu arayüz ve hızlı çözüm üretme disipliniyle tanımlarız.</p></div><div class=\"grid md:grid-cols-2 gap-8\"><div class=\"p-10 border border-line rounded-[32px] hover:bg-ivory/20 transition-colors\"><div class=\"mb-6 h-12 w-12 rounded-full bg-saffron/10 flex items-center justify-center text-saffron font-bold text-xl\">01</div><h3 class=\"font-fraunces text-2xl mb-4 text-ink\">Veri Doğruluğu</h3><p class=\"text-sm text-text-3\">İlanlardaki bilgilerin güncel ve doğru olması için sürekli denetim yapıyoruz. Kaman cevizi gibi hassas ürünlerde sadece gerçek üreticilere yer veriyoruz.</p></div><div class=\"p-10 border border-line rounded-[32px] hover:bg-ivory/20 transition-colors\"><div class=\"mb-6 h-12 w-12 rounded-full bg-saffron/10 flex items-center justify-center text-saffron font-bold text-xl\">02</div><h3 class=\"font-fraunces text-2xl mb-4 text-ink\">Dijital Estetik</h3><p class=\"text-sm text-text-3\">İlanların sunum kalitesini artırarak, bölgedeki mülk ve ürünlerin gerçek değerini yansıtan editoryal bir görünüm sağlıyoruz.</p></div></div><div class=\"bg-ink p-12 rounded-[40px] text-parchment text-center\"><p class=\"font-fraunces text-2xl md:text-3xl opacity-90 italic\">\"Kalitemiz, Kaman halkının bize duyduğu güvenden beslenir.\"</p></div></div>') WHERE slug = 'kalite-politikamiz';

UPDATE custom_pages_i18n SET content = JSON_SET(content, '$.html', '<div class=\"flex flex-col gap-12 lg:gap-24\"><section class=\"grid lg:grid-cols-2 gap-12 lg:gap-24 items-center\"><div><div class=\"eyebrow mb-6\">Misyon</div><h2 class=\"font-fraunces text-4xl lg:text-6xl text-ink leading-tight mb-8\">Yerel Gücü <em>Dijitalle Birleştirmek</em></h2><p class=\"text-xl text-text-2\">Kaman ve Kırşehir bölgesindeki ticaret ekosistemini dijitalleştirerek, herkes için erişilebilir, güvenilir ve prestijli bir pazar yeri oluşturmak temel görevimizdir.</p></div><div class=\"relative aspect-square md:aspect-video rounded-[48px] overflow-hidden bg-muted\"><img src=\"https://images.unsplash.com/photo-1582407947304-fd86f028f716?auto=format&fit=crop&w=1400&q=80\" alt=\"Vizyon\" class=\"object-cover w-full h-full opacity-80\" /></div></section><section class=\"bg-ink text-white p-12 lg:p-24 rounded-[64px] shadow-3xl\"><div class=\"max-w-3xl\"><div class=\"eyebrow mb-6 text-saffron before:bg-saffron\">Vizyon</div><h2 class=\"font-fraunces text-4xl lg:text-7xl mb-12\">Anadolu\'nun <em>Modern İlan Hafızası</em> Olmak</h2><p class=\"text-lg lg:text-2xl text-parchment/60 leading-relaxed\">Kaman\'dan başlayarak tüm Türkiye\'ye yayılan, yerelliği lüks ve profesyonellik ile harmanlayan, güven denince akla gelen ilk dijital platform olmayı hedefliyoruz.</p></div></section></div>') WHERE slug = 'misyon-vizyon';
